-- V21: Move contract attributes to tree-shaped mt_attribute_def (tenant + document_id);
--      drop mt_entity_def and mt_contract_section.

CREATE TABLE mt_attribute_def_new (
    id BIGINT NOT NULL,
    parent_id BIGINT,
    tenant_id BIGINT NOT NULL,
    document_id VARCHAR(30) NOT NULL,
    var_code VARCHAR(50) NOT NULL,
    var_name VARCHAR(300) NOT NULL,
    var_path VARCHAR(500) NOT NULL,
    var_ord BIGINT NOT NULL DEFAULT 0,
    var_type VARCHAR(30) NOT NULL,
    var_cardinality VARCHAR(10) NOT NULL DEFAULT 'SINGLE',
    var_data_type VARCHAR(20) NOT NULL,
    var_value VARCHAR(500),
    var_cdm VARCHAR(500),
    var_list VARCHAR(100),
    code VARCHAR(50),
    name VARCHAR(250),
    is_system BOOLEAN NOT NULL DEFAULT FALSE,
    CONSTRAINT mt_attribute_def_new_pkey PRIMARY KEY (id),
    CONSTRAINT uk_attribute_def_new UNIQUE (tenant_id, document_id, var_code),
    CONSTRAINT mt_attribute_def_new_parent_fk FOREIGN KEY (parent_id) REFERENCES mt_attribute_def_new(id)
);





