DROP TABLE IF EXISTS mt_attribute_def CASCADE;
DROP TABLE IF EXISTS mt_entity_def CASCADE;
DROP TABLE IF EXISTS mt_contract_section CASCADE;

ALTER TABLE mt_attribute_def_new RENAME TO mt_attribute_def;
ALTER TABLE mt_attribute_def RENAME CONSTRAINT mt_attribute_def_new_pkey TO mt_attribute_def_pkey_id;
ALTER TABLE mt_attribute_def RENAME CONSTRAINT uk_attribute_def_new TO uk_attribute_def2;
ALTER TABLE mt_attribute_def RENAME CONSTRAINT mt_attribute_def_new_parent_fk TO mt_attribute_def_parent_fk2;


CREATE SEQUENCE IF NOT EXISTS mt_attribute_def_seq;
SELECT setval('mt_attribute_def_seq', (SELECT COALESCE(MAX(id), 1) FROM mt_attribute_def));

